  };

  const handleCancel = async () => {
    // Implement cancellation logic
    // This would call a server function to cancel in Stripe
  };

  if (loading) return <div>Loading subscription information...</div>;

  return (
    <div className="subscription-manager">
      <h2>Subscription Information</h2>

      {subscription ? (
        <div>
          <p><strong>Current Plan:</strong> {subscription.plan_name || 'Premium'}</p>
          <p><strong>Billing Cycle:</strong> {formatBillingTerm(subscription.billing_term)}</p>
