        setHeaderVisible(false);
        setLoading(false);
        return;
      }

      // Then check database setting
      const { data, error } = await supabase
        .from('admin_settings')
        .select('value')
        .eq('key', 'HEADER_VISIBLE')
        .single();

      if (!error && data) {
        setHeaderVisible(data.value !== 'false');
      }

      setLoading(false);
    };

    fetchHeaderSetting();
