```typescript
// utils/stripeService.ts
import Stripe from 'stripe';
import { createClient } from '@supabase/supabase-js';

// Initialize Supabase client
const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL;
const supabaseServiceKey = process.env.SUPABASE_SERVICE_ROLE_KEY;
const supabase = createClient(supabaseUrl, supabaseServiceKey);

// Helper to get Stripe instance with proper keys
async function getStripeInstance() {
  // Try to get key from environment variable first
  let secretKey = process.env.STRIPE_SECRET_KEY;

  // If not available, try database
  if (!secretKey) {
    const { data, error } = await supabase
      .from('admin_settings')
      .select('value')
      .eq('key', 'STRIPE_SECRET_KEY')
      .single();

    if (error || !data?.value) {
      throw new Error('Stripe secret key not configured');
    }

    secretKey = data.value;
  }

  return new Stripe(secretKey, {
    apiVersion: '2023-10-16', // Use latest API version
  });
}

// Create a subscription
export async function createSubscription(customerId, priceId) {
  const stripe = await getStripeInstance();

  try {
    const subscription = await stripe.subscriptions.create({
      customer: customerId,
      items: [{ price: priceId }],
      expand: ['latest_invoice.payment_intent'],
    });

    return { subscription };
  } catch (error) {
    console.error('Error creating subscription:', error);
    return { error };
  }
}

// Update a subscription
export async function updateSubscription(subscriptionId, newPriceId) {
  const stripe = await getStripeInstance();

  try {
    const subscription = await stripe.subscriptions.retrieve(subscriptionId);

    // Update the subscription item with the new price
    const updatedSubscription = await stripe.subscriptions.update(subscriptionId, {
      items: [{
        id: subscription.items.data[0].id,
        price: newPriceId,
      }],
    });

    return { subscription: updatedSubscription };
  } catch (error) {
    console.error('Error updating subscription:', error);
    return { error };
  }
}

// Cancel a subscription
export async function cancelSubscription(subscriptionId) {
  const stripe = await getStripeInstance();

  try {
    const subscription = await stripe.subscriptions.cancel(subscriptionId);
    return { subscription };
  } catch (error) {
    console.error('Error canceling subscription:', error);
    return { error };
  }
}

// Get customer portal session
export async function createCustomerPortalSession(customerId, returnUrl) {
  const stripe = await getStripeInstance();

  try {
    const session = await stripe.billingPortal.sessions.create({
      customer: customerId,
      return_url: returnUrl,
    });

    return { session };
  } catch (error) {
    console.error('Error creating portal session:', error);
    return { error };
  }
}
```

