// pages/api/stripe/create-portal-session.js
import { createCustomerPortalSession } from '../../../utils/stripeService';
import { getUser } from '../../../utils/supabaseServer';

export default async function handler(req, res) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method not allowed' });
  }

  try {
    // Get authenticated user
    const user = await getUser(req);

    if (!user) {
      return res.status(401).json({ error: 'Unauthorized' });
    }

    // Get customer ID from database
    const { data: subscription } = await supabase
      .from('subscriptions')
      .select('customer_id')
      .eq('uid', user.id)
      .single();

    if (!subscription?.customer_id) {
      return res.status(400).json({ error: 'No subscription found' });
    }

    // Create portal session
    const { session, error } = await createCustomerPortalSession(
      subscription.customer_id,
      `${req.headers.origin}/settings`
    );

    if (error) {
      return res.status(400).json({ error });
    }

    res.status(200).json({ url: session.url });
  } catch (error) {
    console.error('Error creating portal session:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
}
